import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push({ v, start, end });
    }

    // Dijkstra's setup: priority queue and distance array
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    const pq = new MinPriorityQueue({ priority: (entry) => entry.time });
    pq.enqueue({ node: 0, time: 0 });

    while (!pq.isEmpty()) {
        const { node, time } = pq.dequeue().element;
        if (node === n - 1) {
            return time;
        }
        if (time > dist[node]) {
            continue;
        }
        // Option 1: stay at current node (time + 1)
        if (time + 1 < dist[node]) {
            dist[node] = time + 1;
            pq.enqueue({ node, time: time + 1 });
        }
        // Option 2: take available edges
        for (const edge of adj[node]) {
            const { v, start, end } = edge;
            const t = Math.max(time, start);
            if (t <= end && t + 1 < dist[v]) {
                dist[v] = t + 1;
                pq.enqueue({ node: v, time: t + 1 });
            }
        }
    }

    return dist[n - 1] === Infinity ? -1 : dist[n - 1];
}

